---@class StructPositionInfo
local StructPositionInfo = LxClass("StructPositionInfo", nil)

function StructPositionInfo:StructPositionInfo()

end

function StructPositionInfo:CreateByPb(pb)
    self.name = pb.name
    self.image = pb.image
    self.imageType = pb.imageType
    self.position = pb.position
    self.pid = pb.pid
    self.guildId = pb.guildId

end

function StructPositionInfo:GetPrefab()
    if not self.prefab then
        if self.imageType == 1 then
            self.prefab = gModelHero:GetHeroEffectPrefab(self.image)
            elseif self.imageType == 2 then
            self.prefab = gModelPlayer:GetRoleAdventurePrefab(self.image)
        end
    end

    return self.prefab
end




return StructPositionInfo